# Infinite sequences
def naturals():
    n = 0
    while True:
        yield n
        n += 1

def take(n, iterable):
    for i, item in enumerate(iterable):
        if i >= n:
            break
        yield item

print(list(take(5, naturals())))  # [0, 1, 2, 3, 4]

