# yield from forwards send()
def receiver():
    total = 0
    while True:
        value = yield total
        if value is None:
            return total
        total += value

def proxy():
    result = yield from receiver()
    print(f"Total: {result}")

p = proxy()
next(p)           # prime
print(p.send(10))  # 10
print(p.send(20))  # 30
try:
    p.send(None)   # triggers return in receiver
except StopIteration:
    pass
# Total: 30

# Tree traversal with yield from
class TreeNode:
    def __init__(self, value, children=None):
        self.value = value
        self.children = children or []

def traverse(node):
    yield node.value
    for child in node.children:
        yield from traverse(child)  # recursive delegation

tree = TreeNode(1, [
    TreeNode(2, [TreeNode(4), TreeNode(5)]),
    TreeNode(3, [TreeNode(6)])
])

print(list(traverse(tree)))  # [1, 2, 4, 5, 3, 6]

