# Log file processing pipeline
def read_lines(text):
    """Source: split text into lines."""
    for line in text.strip().split("\n"):
        yield line

def strip_comments(lines):
    """Transform: remove comments."""
    for line in lines:
        if not line.strip().startswith("#"):
            yield line

def strip_whitespace(lines):
    """Transform: strip leading/trailing whitespace."""
    for line in lines:
        stripped = line.strip()
        if stripped:  # skip empty lines
            yield stripped

def to_uppercase(lines):
    """Transform: convert to uppercase."""
    for line in lines:
        yield line.upper()

# Build pipeline
log_text = """
# Config file
host = localhost
# Database settings
port = 5432
user = admin

password = secret
"""

pipeline = to_uppercase(
    strip_whitespace(
        strip_comments(
            read_lines(log_text)
        )
    )
)

for line in pipeline:
    print(line)
