# Data processing pipeline
def generate_numbers(n):
    for i in range(n):
        yield i

def square(numbers):
    for n in numbers:
        yield n ** 2

def filter_even(numbers):
    for n in numbers:
        if n % 2 == 0:
            yield n

def accumulate(numbers):
    total = 0
    for n in numbers:
        total += n
        yield total

# Pipeline: generate -> square -> filter even -> accumulate
pipeline = accumulate(filter_even(square(generate_numbers(10))))
print(list(pipeline))  # [0, 4, 20, 56, 120]

# More readable: assign each stage
source = generate_numbers(10)
squared = square(source)
evens = filter_even(squared)
running_total = accumulate(evens)
print(list(running_total))  # [0, 4, 20, 56, 120]

# Generic pipeline builder
def pipe(data, *functions):
    for func in functions:
        data = func(data)
    return data

result = pipe(
    range(10),
    square,
    filter_even,
    accumulate
)
print(list(result))  # [0, 4, 20, 56, 120]

# Real-world: CSV processing
def parse_csv_lines(lines):
    for line in lines:
        yield line.split(",")

def select_columns(rows, indices):
    for row in rows:
        yield [row[i] for i in indices]

def filter_rows(rows, col, value):
    for row in rows:
        if row[col] == value:
            yield row

csv_data = [
    "Alice,30,NYC",
    "Bob,25,LA",
    "Charlie,35,NYC",
    "Diana,28,LA"
]

pipeline = select_columns(
    filter_rows(
        parse_csv_lines(iter(csv_data)),
        col=2, value="NYC"
    ),
    indices=[0, 1]
)

for row in pipeline:
    print(row)
# ['Alice', '30']
# ['Charlie', '35']

